"use strict";(self.webpackChunkastrology_garden=self.webpackChunkastrology_garden||[]).push([["6605"],{5071(n,e,i){i.r(e),i.d(e,{metadata:()=>o,default:()=>p,frontMatter:()=>r,contentTitle:()=>t,toc:()=>l,assets:()=>c});var o=JSON.parse('{"id":"Stellar bodies/saturn","title":"saturn","description":"Principle:","source":"@site/docs/Stellar bodies/saturn.md","sourceDirName":"Stellar bodies","slug":"/Stellar bodies/saturn","permalink":"/docs/Stellar bodies/saturn","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/Stellar bodies/saturn.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"pluto","permalink":"/docs/Stellar bodies/pluto"},"next":{"title":"sun","permalink":"/docs/Stellar bodies/sun"}}'),a=i(4848),s=i(8453);let r={},t,c={},l=[{value:"T\u0142umaczenie na j\u0119zyk polski (Translation)",id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",level:3}];function d(n){let e={h3:"h3",li:"li",p:"p",ul:"ul",...(0,s.R)(),...n.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(e.p,{children:"Principle:"}),"\n",(0,a.jsx)(e.p,{children:"Inhibition, concentration."}),"\n",(0,a.jsx)(e.p,{children:"Psychological Correspondence:"}),"\n",(0,a.jsxs)(e.ul,{children:["\n",(0,a.jsxs)(e.li,{children:["\n",(0,a.jsx)(e.p,{children:"Concentration, consolidation, perseverance, seriousness, the ability to learn from experience, economy."}),"\n"]}),"\n",(0,a.jsxs)(e.li,{children:["\n",(0,a.jsx)(e.p,{children:"Inhibition, melancholy, reserve and taciturnity, increasing loneliness, isolation, eccentricity, distrust, stinginess, lack of adaptability."}),"\n"]}),"\n"]}),"\n",(0,a.jsx)(e.p,{children:"Biological Correspondence:"}),"\n",(0,a.jsx)(e.p,{children:"The bony structure, the process of hardening up, stone-formation, the loss of organs. Old age."}),"\n",(0,a.jsx)(e.p,{children:"Sociological Correspondence:"}),"\n",(0,a.jsx)(e.p,{children:"Hard-working, inhibited or sad people. Agriculture, mining, real estate."}),"\n",(0,a.jsx)(e.p,{children:"Position in Houses and Signs:"}),"\n",(0,a.jsx)(e.p,{children:"I. Ambition, diligence and industry, endurance, obstinacy, self-restraint, modesty, serious mode of working. \u2013 The desire to rule other people, self-will, defiance, the tendency to go one's way alone, selfishness."}),"\n",(0,a.jsx)(e.p,{children:"II. Perseverance, enduring energy, the application of method, economy, the urge to acquire possessions or property. \u2013 A conservative outlook, inertia, inhibitions make advancement in the world difficult."}),"\n",(0,a.jsx)(e.p,{children:"III. A great zeal for study, thoroughness in one's work, logical thinking, preoccupation with difficult problems, conscientiousness. \u2013 Small capacity for adapting oneself to circumstances, awkwardness and clumsiness, shyness."}),"\n",(0,a.jsx)(e.p,{children:"IV. Reserve, a controlled emotional life, a love of independence, difficult contact with family-members. \u2013 Hypersensitiveness, discontent, modest or aggravating circumstances are due to family-ties."}),"\n",(0,a.jsx)(e.p,{children:"V. Reliability, loyalty, simplicity, inhibitions with regard to social contacts, dislike of formalities, shyness, caution, diplomacy, inhibited sex-expression."}),"\n",(0,a.jsx)(e.p,{children:"VI. Care and attention, meticulous accuracy, correctness, seriousness, thoroughness, responsibility, discreetness, a sense of criticism. \u2013 A nagging nature, pedantry, the desire to act alone and not in unison with others, the misunderstood person."}),"\n",(0,a.jsx)(e.p,{children:"VII. An industrious and loyal colleague or partner, a strong sense of duty, conscientiousness, reliability. \u2013 Inhibitions in communal life or in contacts with others, discontent."}),"\n",(0,a.jsx)(e.p,{children:'VIII. Obstinacy, a serious outlook on life, the urge to probe or to delve deeply into difficult problems, the tendency to occupy one\'s mind with metaphysical spheres of knowledge, skill, endurance. \u2013 Melancholy, transformations. The experience of spiritual rebirth or of "Stirb und werde" (this is a German phrase which cannot be rendered accurately in English).'}),"\n",(0,a.jsx)(e.p,{children:"IX. A strong sense of justice, religious aspirations, asceticism, philosophical research, prudence, a talent for the legal profession. \u2013 Separation from one's native country, the desire to emigrate. \u2013 Lack of understanding and wisdom leads to doubts."}),"\n",(0,a.jsx)(e.p,{children:"X. Self-restraint. A strong will, concentration, industry, endurance, economy, diplomacy, slow but sure advancement in life. \u2013 One-sidedness and partiality, self-willedness, an egocentric nature."}),"\n",(0,a.jsx)(e.p,{children:"XI. Harmonious association of planning with realisation, or of ideals with practical creativeness. A reliable partner. Social aspirations. Eccentric and extravagant expectations lead to disappointment, ambitious plans without a sound foundation."}),"\n",(0,a.jsx)(e.p,{children:"XII. Modesty, reserve, difficult work in seclusion (often without recognition). Timidity, growing loneliness, depressions, a struggle with opponents."}),"\n",(0,a.jsx)(e.h3,{id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",children:"T\u0142umaczenie na j\u0119zyk polski (Translation)"}),"\n",(0,a.jsx)(e.p,{children:"SATURN"}),"\n",(0,a.jsx)(e.p,{children:"Zasada:"}),"\n",(0,a.jsx)(e.p,{children:"Zahamowanie, koncentracja."}),"\n",(0,a.jsx)(e.p,{children:"Korespondencja psychologiczna:"}),"\n",(0,a.jsxs)(e.ul,{children:["\n",(0,a.jsxs)(e.li,{children:["\n",(0,a.jsx)(e.p,{children:"Koncentracja, konsolidacja, wytrwa\u0142o\u015B\u0107, powaga, zdolno\u015B\u0107 uczenia si\u0119 z do\u015Bwiadczenia, oszcz\u0119dno\u015B\u0107."}),"\n"]}),"\n",(0,a.jsxs)(e.li,{children:["\n",(0,a.jsx)(e.p,{children:"Zahamowanie, melancholia, rezerwa i ma\u0142om\xf3wno\u015B\u0107, rosn\u0105ca samotno\u015B\u0107, izolacja, ekscentryczno\u015B\u0107, nieufno\u015B\u0107, sk\u0105pstwo, brak zdolno\u015Bci adaptacji."}),"\n"]}),"\n"]}),"\n",(0,a.jsx)(e.p,{children:"Korespondencja biologiczna:"}),"\n",(0,a.jsx)(e.p,{children:"Struktura kostna, proces twardnienia, powstawanie kamieni, utrata narz\u0105d\xf3w. Staro\u015B\u0107."}),"\n",(0,a.jsx)(e.p,{children:"Korespondencja socjologiczna:"}),"\n",(0,a.jsx)(e.p,{children:"Ci\u0119\u017Cko pracuj\u0105cy, zahamowani lub smutni ludzie. Rolnictwo, g\xf3rnictwo, nieruchomo\u015Bci."}),"\n",(0,a.jsx)(e.p,{children:"Pozycja w domach i znakach:"}),"\n",(0,a.jsx)(e.p,{children:"I. Ambicja, pilno\u015B\u0107 i pracowito\u015B\u0107, wytrwa\u0142o\u015B\u0107, uparto\u015B\u0107, pow\u015Bci\u0105gliwo\u015B\u0107, skromno\u015B\u0107, powa\u017Cny tryb pracy. \u2013 Pragnienie rz\u0105dzenia innymi lud\u017Ami, samowola, przekora, tendencja do chodzenia w\u0142asn\u0105 drog\u0105 w samotno\u015Bci, samolubstwo."}),"\n",(0,a.jsx)(e.p,{children:"II. Wytrwa\u0142o\u015B\u0107, trwa\u0142a energia, stosowanie metod, oszcz\u0119dno\u015B\u0107, pragnienie zdobywania posiad\u0142o\u015Bci lub w\u0142asno\u015Bci. \u2013 Konserwatywne spojrzenie, bezw\u0142ad (bierno\u015B\u0107), zahamowania utrudniaj\u0105ce awans w \u015Bwiecie."}),"\n",(0,a.jsx)(e.p,{children:"III. Wielki zapa\u0142 do nauki, dok\u0142adno\u015B\u0107 w pracy, logiczne my\u015Blenie, zajmowanie si\u0119 trudnymi problemami, sumienno\u015B\u0107. \u2013 Ma\u0142a zdolno\u015B\u0107 dostosowywania si\u0119 do okoliczno\u015Bci, niezr\u0119czno\u015B\u0107 i niezdarno\u015B\u0107, nie\u015Bmia\u0142o\u015B\u0107."}),"\n",(0,a.jsx)(e.p,{children:"IV. Rezerwa, kontrolowane \u017Cycie emocjonalne, zami\u0142owanie do niezale\u017Cno\u015Bci, trudny kontakt z cz\u0142onkami rodziny. \u2013 Nadwra\u017Cliwo\u015B\u0107, niezadowolenie, skromne lub pogarszaj\u0105ce si\u0119 warunki wynikaj\u0105ce z wi\u0119zi rodzinnych."}),"\n",(0,a.jsx)(e.p,{children:"V. Niezawodno\u015B\u0107, lojalno\u015B\u0107, prostota, zahamowania w kontaktach towarzyskich, niech\u0119\u0107 do formalno\u015Bci, nie\u015Bmia\u0142o\u015B\u0107, ostro\u017Cno\u015B\u0107, dyplomacja, zahamowana ekspresja seksualna."}),"\n",(0,a.jsx)(e.p,{children:"VI. Troska i uwaga, skrupulatna dok\u0142adno\u015B\u0107, poprawno\u015B\u0107, powaga, dok\u0142adno\u015B\u0107, odpowiedzialno\u015B\u0107, dyskrecja, zmys\u0142 krytycyzmu. \u2013 Zrz\u0119dliwa natura, pedanteria, pragnienie dzia\u0142ania w pojedynk\u0119, a nie w harmonii z innymi, osoba niezrozumiana."}),"\n",(0,a.jsx)(e.p,{children:"VII. Pracowity i lojalny wsp\xf3\u0142pracownik lub partner, silne poczucie obowi\u0105zku, sumienno\u015B\u0107, niezawodno\u015B\u0107. \u2013 Zahamowania w \u017Cyciu wsp\xf3lnotowym lub w kontaktach z innymi, niezadowolenie."}),"\n",(0,a.jsx)(e.p,{children:"VIII. Uparto\u015B\u0107, powa\u017Cne spojrzenie na \u017Cycie, pragnienie zg\u0142\u0119biania lub zag\u0142\u0119biania si\u0119 w trudne problemy, tendencja do zajmowania umys\u0142u metafizycznymi sferami wiedzy, umiej\u0119tno\u015Bci, wytrwa\u0142o\u015B\u0107. \u2013 Melancholia, transformacje. Do\u015Bwiadczenie duchowego odrodzenia lub \u201EStirb und werde\u201D (to niemiecka fraza, kt\xf3rej nie da si\u0119 dok\u0142adnie odda\u0107 w j\u0119zyku angielskim)."}),"\n",(0,a.jsx)(e.p,{children:"IX. Silne poczucie sprawiedliwo\u015Bci, aspiracje religijne, asceza, badania filozoficzne, roztropno\u015B\u0107, talent do profesji prawniczej. \u2013 Odseparowanie od ojczystego kraju, pragnienie emigracji. \u2013 Brak zrozumienia i m\u0105dro\u015Bci prowadzi do w\u0105tpliwo\u015Bci."}),"\n",(0,a.jsx)(e.p,{children:"X. Pow\u015Bci\u0105gliwo\u015B\u0107. Silna wola, koncentracja, pracowito\u015B\u0107, wytrwa\u0142o\u015B\u0107, oszcz\u0119dno\u015B\u0107, dyplomacja, powolny, lecz pewny awans w \u017Cyciu. \u2013 Jednostronno\u015B\u0107 i stronniczo\u015B\u0107, uparto\u015B\u0107 (samowola), egocentryczna natura."}),"\n",(0,a.jsx)(e.p,{children:"XI. Harmonijne \u0142\u0105czenie planowania z realizacj\u0105 lub idea\u0142\xf3w z praktyczn\u0105 kreatywno\u015Bci\u0105. Niezawodny partner. Aspiracje spo\u0142eczne. Ekscentryczne i wyg\xf3rowane oczekiwania prowadz\u0105 do rozczarowania, ambitne plany bez solidnych fundament\xf3w."}),"\n",(0,a.jsx)(e.p,{children:"XII. Skromno\u015B\u0107, rezerwa, trudna praca w odosobnieniu (cz\u0119sto bez uznania). Nie\u015Bmia\u0142o\u015B\u0107, rosn\u0105ca samotno\u015B\u0107, depresje, walka z przeciwnikami."})]})}function p(n={}){let{wrapper:e}={...(0,s.R)(),...n.components};return e?(0,a.jsx)(e,{...n,children:(0,a.jsx)(d,{...n})}):d(n)}},8453(n,e,i){i.d(e,{R:()=>r,x:()=>t});var o=i(6540);let a={},s=o.createContext(a);function r(n){let e=o.useContext(s);return o.useMemo(function(){return"function"==typeof n?n(e):{...e,...n}},[e,n])}function t(n){let e;return e=n.disableParentContext?"function"==typeof n.components?n.components(a):n.components||a:r(n.components),o.createElement(s.Provider,{value:e},n.children)}}}]);